local method = ngx.req.get_method()
local uri = ngx.var.uri

if uri == "/session/create" and method == "POST" then
    ngx.req.read_body()
    local args = ngx.req.get_post_args()
    local user_id = args and args.user_id

    if not user_id then
        ngx.status = 400
        ngx.say("Missing user_id parameter")
        return
    end

    local manager = SessionManager.new({
        session_ttl = 7200,
        token_length = 32,
        nonce_length = 16
    })

    local session, err = manager:create_session(user_id, { ip = ngx.var.remote_addr })
    if not session then
        ngx.status = 500
        ngx.say("Failed to create session: " .. (err or "unknown error"))
        return
    end

    ngx.header["Set-Cookie"] = string.format(
        "session_token=%s; Path=/; HttpOnly; Secure; SameSite=Strict; Max-Age=%d",
        session.token, 7200
    )

    local cjson = require("cjson")
    ngx.status = 200
    ngx.say(cjson.encode({
        status = "ok",
        session_token = session.token,
        csrf_token = session.csrf_token,
        nonce = session.nonce,
        expires_at = session.expires_at
    }))

elseif uri == "/session/validate" and method == "GET" then
    local token = ngx.var.cookie_session_token
    if not token then
        ngx.status = 401
        ngx.say("No session token provided")
        return
    end

    local manager = SessionManager.new()
    local session, err = manager:validate_session(token)
    if not session then
        ngx.status = 401
        ngx.say("Invalid session: " .. (err or "unknown error"))
        return
    end

    local cjson = require("cjson")
    ngx.status = 200
    ngx.say(cjson.encode({
        status = "valid",
        user_id = session.user_id,
        expires_at = session.expires_at
    }))

elseif uri == "/session/refresh" and method == "POST" then
    local token = ngx.var.cookie_session_token
    if not token then
        ngx.status = 401
        ngx.say("No session token provided")
        return
    end

    local manager = SessionManager.new()
    local session, err = manager:refresh_session(token)
    if not session then
        ngx.status = 401
        ngx.say("Failed to refresh session: " .. (err or "unknown error"))
        return
    end

    local cjson = require("cjson")
    ngx.status = 200
    ngx.say(cjson.encode({
        status = "refreshed",
        new_nonce = session.nonce,
        expires_at = session.expires_at
    }))

elseif uri == "/session/destroy" and method == "POST" then
    local token = ngx.var.cookie_session_token
    if not token then
        ngx.status = 400
        ngx.say("No session token provided")
        return
    end

    local manager = SessionManager.new()
    manager:destroy_session(token)

    ngx.header["Set-Cookie"] = "session_token=; Path=/; HttpOnly; Secure; Max-Age=0"
    ngx.status = 200
    ngx.say("Session destroyed")

elseif uri == "/token/generate" and method == "GET" then
    local session_token = generate_session_token()
    local nonce = generate_nonce(16)
    local csrf = generate_csrf_token()

    local cjson = require("cjson")
    ngx.status = 200
