        session_token = session_token,
        nonce = nonce,
        csrf_token = csrf,
        generated_at = os.time()
    }))

else
    ngx.status = 404
    ngx.say("Not found. Available endpoints:")
    ngx.say("  POST /session/create   - Create a new session (requires user_id)")
    ngx.say("  GET  /session/validate - Validate current session")
    ngx.say("  POST /session/refresh  - Refresh session TTL and nonce")
    ngx.say("  POST /session/destroy  - Destroy current session")
    ngx.say("  GET  /token/generate   - Generate standalone tokens")
end